// Clean and extract only useful fields from the Fathom webhook payload

const body = $json.body || $json;

// Core meeting fields
const meetingTitle = body.meeting_title || body.title || null;
const meetingId = body.recording_id || null;
const meetingUrl = body.share_url || null;
const transcriptLanguage = body.transcript_language || null;

// ✅ Meeting anchor (what your prompt’s date rules require)
const meetingStartAt =
  body.meetingStartAt ||
  body.scheduled_start_time ||
  body.recording_start_time ||
  body.start_time ||
  null;

const meetingEndAt =
  body.scheduled_end_time ||
  body.recording_end_time ||
  body.end_time ||
  null;

// Optional convenience field (some prompts prefer this)
const meetingDate = meetingStartAt ? String(meetingStartAt).slice(0, 10) : null;

// ✅ Timezone hint (if present; otherwise inferred from Z)
const meetingTimezone =
  $input.first().json["Time Zone"] || '';

// Invitees (flatten to strings to reduce schema confusion)
const invitees = (body.calendar_invitees || []).map(i => {
  const name = i.display_name || i.name || "Unknown";
  const email = i.email || i.matched_calendar_invitee_email || "";
  return email ? `${name} <${email}>` : name;
});

// Transcript lines
const transcriptLines = (body.transcript || []).map(t => {
  const speaker = t.speaker?.display_name || t.speaker?.name || "Unknown";
  const ts = t.timestamp ? `[${t.timestamp}]` : "";
  return `${ts} ${speaker}: ${t.text || ""}`.trim();
});

// Summary if present
const summary =
  body.default_summary?.markdown_formatted ||
  body.summary ||
  null;

// ✅ Return in n8n item format
return [{
  json: {
    meetingId,
    meetingTitle,
    meetingUrl,
    transcriptLanguage,
    invitees,
    meetingStartAt,     // key for your date inference
    meetingEndAt,
    meetingDate,        // helpful fallback
    meetingTimezone,
    summary,
    transcript: transcriptLines.join("\n"),
  }
}];

// This Function node expects the AI Agent's result in item.json.output
// Node type MUST be "Function" (not "Function Item")

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

const newItems = [];

for (const item of items) {
  let data;

  // 1) Get the agent output
  let raw = item.json.output;

  if (raw && typeof raw === 'object') {
    // already parsed
    data = raw;
  } else if (typeof raw === 'string') {
    raw = raw.trim();

    // strip ```json fences if present
    if (raw.startsWith('```')) {
      raw = raw.replace(/^```[a-zA-Z]*\s*/m, '');
      raw = raw.replace(/```[\s]*$/m, '');
      raw = raw.trim();
    }

    if (!raw) {
      newItems.push(item);
      continue;
    }

    try {
      data = JSON.parse(raw);
    } catch (err) {
      newItems.push({
        json: {
          ...item.json,
          _parseError: 'Failed to parse AI output as JSON',
          _rawOutput: raw,
          _errorMessage: err.message,
        },
      });
      continue;
    }
  } else {
    // no usable output
    newItems.push(item);
    continue;
  }

  // 2) Pull pieces out
  const meta      = data.meta || {};
  const sections = data.sections || {};
  const email    = data.email || {};

  const painPoints  = sections.pain_points || [];
  const va          = sections.va_discussion || {};
  const milestones  = sections.milestones || [];
  const nextMeeting = sections.next_meeting || {};
  const bodyText    = email.body || '';

  // 3) Subject: Meeting Summary - {clientName} - {meetingTitle}
  const clientName   = meta.clientName || meta.client || '';
  const meetingTitle = meta.meetingTitle || '';
  let subjectOut     = email.subject || '';

  if (clientName || meetingTitle) {
    const clientLabel = clientName || 'Client';
    const titleLabel  = meetingTitle || 'Meeting';
    subjectOut = `Meeting Summary - ${clientLabel} - ${titleLabel}`;
  }

  // 4) Key Focus Areas & Opportunities
  let painPointsSection = '';
  if (Array.isArray(painPoints) && painPoints.length > 0) {
    const itemsList = painPoints.map(p => {
      const category = p.category ? `${escapeHtml(p.category)}: ` : '';
      const summary  = escapeHtml(p.summary || '');
      return `<li style="margin-bottom:8px;font-size:14px;line-height:20px;">${category}${summary}</li>`;
    });

    painPointsSection = `
      <div style="margin-top:16px; margin-bottom:16px;">
        <h3 style="margin:0 0 8px 0;">Key Focus Areas &amp; Opportunities</h3>
        <ul style="margin:0 0 10px 20px; padding:0 0 0 18px; list-style-type:disc;">
          ${itemsList.join('')}
        </ul>
      </div>
    `;
  }

  // ========================================================================
  // 5) VA Discussion (UPDATED)
  // Logic: Parse tasks and timeline. Check if they are empty or "None discussed".
  // Only render if there is actual content.
  // ========================================================================
  let vaSection = '';

  // a. Get raw data safely
  let rawTasks = Array.isArray(va.primary_tasks) ? va.primary_tasks : [];
  let rawTimeline = (va.onboarding_timeline || '').trim();

  // b. Filter Tasks: remove empty strings or "None discussed" variations
  const primaryTasks = rawTasks.filter(t => {
    if (!t || typeof t !== 'string') return false;
    // Normalize: remove trailing dot, trim whitespace, convert to lowercase
    const normalized = t.trim().replace(/\.$/, '').toLowerCase();
    return normalized !== 'none discussed' && normalized !== '';
  });

  // c. Check Timeline: is it empty or "None discussed"?
  let isTimelineEmpty = false;
  const normTimeline = rawTimeline.toLowerCase().replace(/\.$/, '');
  if (!rawTimeline || normTimeline === 'none discussed' || normTimeline === '') {
      isTimelineEmpty = true;
  }

  // d. Decision: Do we show the section?
  const hasVaContent = primaryTasks.length > 0 || !isTimelineEmpty;

  if (hasVaContent) {
    const tasksList = primaryTasks.length
      ? `<ul style="margin:4px 0 10px 20px; padding:0 0 0 18px; list-style-type:disc;">
           ${primaryTasks.map(t => `<li style="font-size:14px;line-height:20px;">${escapeHtml(t)}</li>`).join('')}
         </ul>`
      : '';

    let timelineText = rawTimeline;
    const tlLower = timelineText.toLowerCase();
    if (tlLower.includes('ongoing') && (tlLower.includes('workflow') || tlLower.includes('process'))) {
      timelineText = 'We will continue refining this workflow over time.';
    }

    const timelineHtml = !isTimelineEmpty
      ? `<p style="margin:8px 0 0 0;font-size:14px;line-height:20px;"><strong>Onboarding / Timeline:</strong> ${escapeHtml(timelineText)}</p>`
      : '';

    vaSection = `
      <div style="margin-top:16px; margin-bottom:16px;">
        <h3 style="margin:0 0 8px 0;">VA Discussion</h3>
        ${primaryTasks.length ? `<p style="margin:8px 0 4px 0;font-size:14px;line-height:20px;"><strong>Primary Tasks:</strong></p>${tasksList}` : ''}
        ${timelineHtml}
      </div>
    `;
  }
  // ========================================================================


  // 6) Milestones table
  let milestonesSection = '';
  const realMilestones = (Array.isArray(milestones) ? milestones : []).filter(m => {
    const desc = (m.description || m.name || '').trim().toLowerCase();
    return desc && desc !== 'none discussed.';
  });

  if (realMilestones.length > 0) {
    milestonesSection = `
      <div style="margin-top:16px; margin-bottom:16px;">
        <h3 style="margin:0 0 8px 0;">Milestones</h3>
        <table border="1" cellpadding="6" cellspacing="0"
               style="border-collapse:collapse; width:100%; border:1px solid #e5e7eb; table-layout:fixed; font-size:14px;line-height:20px;">
          <colgroup>
            <col style="width:50%;">
            <col style="width:20%;">
            <col style="width:15%;">
            <col style="width:15%;">
          </colgroup>
          <thead>
            <tr style="background:#f9fafb;">
              <th style="text-align:center;font-size:14px;line-height:20px;">Milestone</th>
              <th style="text-align:center;font-size:14px;line-height:20px;">Owner</th>
              <th style="text-align:center;font-size:14px;line-height:20px;">Status</th>
              <th style="text-align:center;font-size:14px;line-height:20px;">Target Date</th>
            </tr>
          </thead>
          <tbody>
            ${realMilestones.map(m => {
              let name = (m.name || '').trim();
              const fullDesc = String(m.description || '').trim();
              if (!name) {
                name = fullDesc.split(/\.|\n/)[0] || fullDesc;
              }

              const descHtml = fullDesc
                ? `<div style="margin-top:4px;font-size:14px;line-height:20px;color:#4b5563;">
                     ${escapeHtml(fullDesc)}
                   </div>`
                : '';

              return `
                <tr>
                  <td style="vertical-align:top;font-size:14px;line-height:20px;">
                    <strong>${escapeHtml(name)}</strong>
                    ${descHtml}
                  </td>
                  <td style="vertical-align:top; text-align:center;font-size:14px;line-height:20px;">${escapeHtml(m.owner || 'TBD')}</td>
                  <td style="vertical-align:top; text-align:center;font-size:14px;line-height:20px;">${escapeHtml(m.status || 'Planned')}</td>
                  <td style="vertical-align:top; text-align:center;font-size:14px;line-height:20px;">${escapeHtml(m.target_date || 'TBD')}</td>
                </tr>
              `;
            }).join('')}
          </tbody>
        </table>
      </div>
    `;
  }

  // 7) Next FPEC Session
  let nextMeetingSection = '';
  if (nextMeeting && typeof nextMeeting === 'object' && Object.keys(nextMeeting).length > 0) {
    const rawDate = (nextMeeting.date || '').trim();
    const rawTime = (nextMeeting.time || '').trim();
    const nmTz    = (nextMeeting.timezone || '').trim();
    const nmNote  = nextMeeting.notes || 'Next FPEC session';

    const isDateReal = rawDate && rawDate.toUpperCase() !== 'TBD';
    const isTimeReal = rawTime && rawTime.toUpperCase() !== 'TBD';

    if (isDateReal || isTimeReal) {
      const parts = [];
      if (isDateReal) parts.push(rawDate);
      if (isTimeReal) parts.push(rawTime);
      if (nmTz)       parts.push(nmTz);

      const whenText = parts.join(' • ') || 'To be scheduled';

      nextMeetingSection = `
        <div style="margin-top:16px; margin-bottom:16px;">
          <p style="margin:0; font-size:14px; line-height:20px;">
            <strong>${escapeHtml(nmNote)}:</strong>
            ${escapeHtml(whenText)}
          </p>
        </div>
      `;
    }
  }

  // 8) Intro from plain-text body (skip duplicated sections)
  const lines = String(bodyText || '').split('\n');
  const introParts = [];
  let i = 0;
  let signoffLines = [];

  while (i < lines.length) {
    let line = lines[i].trim();

    if (!line) {
      i++;
      continue;
    }

    // Skip duplicated headers
    if (/^Key Focus Areas[:]?/i.test(line) || /^Milestones[:]?/i.test(line)) {
      i++;
      while (i < lines.length) {
        const l2 = lines[i].trim();
        if (!l2) { i++; continue; }
        if (!l2.startsWith('- ')) break;
        i++;
      }
      continue;
    }

    if (line === 'Key Discussion Points:') {
      i++;
      while (i < lines.length) {
        const l2 = lines[i].trim();
        if (!l2) { i++; continue; }
        if (!l2.startsWith('- ')) break;
        i++;
      }
      continue;
    }

    if (/^next steps[:]?/i.test(line)) {
      i++;
      while (i < lines.length) {
        const l2 = lines[i].trim();
        if (!l2) { i++; continue; }
        if (!l2.startsWith('- ')) break;
        i++;
      }
      continue;
    }

    if (/^best\b/i.test(line)) {
      signoffLines.push(line);
      i++;
      while (i < lines.length) {
        const l2 = lines[i].trim();
        if (!l2) break;
        signoffLines.push(l2);
        i++;
      }
      continue;
    }

    const paraLines = [line];
    i++;

    while (i < lines.length) {
      const l2 = lines[i].trim();
      if (
        !l2 ||
        l2 === 'Key Discussion Points:' ||
        /^next steps[:]?$/i.test(l2) ||
        /^best\b/i.test(l2) ||
        l2.startsWith('- ')
      ) {
        break;
      }
      paraLines.push(l2);
      i++;
    }

    const paraText = paraLines.join(' ');
    if (/Please let me know if you have any questions/i.test(paraText)) {
      continue;
    }

    introParts.push(`<p style="margin:0 0 16px 0; font-size:14px; line-height:20px;">${escapeHtml(paraText)}</p>`);
  }

  // 9) Sign-off
  let signName = '';
  if (signoffLines.length > 0) {
    for (let j = signoffLines.length - 1; j >= 0; j--) {
      const l = signoffLines[j].trim();
      if (l && !/^best\b/i.test(l)) {
        signName = l;
        break;
      }
    }
  }

  if (!signName) {
    signName = 'SV Process Engineering Team';
  }

  const signoffHtml = [
    `<p style="margin:0 0 12px 0; font-size:14px; line-height:20px;">Best regards,</p>`,
    `<p style="margin:0 0 12px 0; font-size:14px; line-height:20px;">${escapeHtml(signName)}</p>`
  ].join('\n');

  // 10) Combine sections
  const detailSections = [
    painPointsSection,
    vaSection,
    milestonesSection,
    nextMeetingSection,
  ].filter(Boolean).join('\n');

  let detailedNotesBlock = detailSections ? detailSections : '';

  const customClosing = `<p style="margin:16px 0 12px 0; font-size:14px; line-height:20px;">If there’s anything I missed or if you’d like to adjust any of the milestones, please feel free to let me know.</p>`;

  let finalHtml = '';
  finalHtml += introParts.join('\n');
  if (detailedNotesBlock) {
    finalHtml += '\n' + detailedNotesBlock;
  }
  finalHtml += '\n' + customClosing;
  finalHtml += '\n' + signoffHtml;

  // 11) Wrap in card layout
  const safeMeetingTitle = meetingTitle || 'Minutes of the Meeting';

  const headerBlock = `
    <table role="presentation" cellpadding="0" cellspacing="0" width="100%">
      <tr>
        <td align="center" style="padding:24px;">
          <table role="presentation" cellpadding="0" cellspacing="0" width="720" style="max-width:720px;background:#ffffff;border-radius:12px;overflow:hidden;border:1px solid #e5e7eb;">
            <tr>
              <td style="background:#ea7b21;color:#ffffff;padding:20px 28px;border-radius:12px 12px 0 0;text-align:center;">
                <h1 style="margin:0 0 4px 0;font-size:22px;line-height:28px;font-weight:700;font-family:Arial,Helvetica,sans-serif;">
                  Minutes of the Meeting
                </h1>
                <p style="margin:0;font-size:13px;line-height:18px;font-family:Arial,Helvetica,sans-serif;">
                  ${escapeHtml(safeMeetingTitle)}
                </p>
              </td>
            </tr>
            <tr>
              <td style="padding:24px 28px 28px 28px;background:#ffffff;font-size:14px;line-height:20px;">
                ${finalHtml.trim()}
              </td>
            </tr>
          </table>
        </td>
      </tr>
    </table>
  `.trim();

  const fullHtml = `
<!DOCTYPE html>
<html>
  <head>
    <meta charset="utf-8" />
    <title>${escapeHtml(subjectOut || '')}</title>
  </head>
  <body style="margin:0;padding:0;background:#f3f4f6;font-family:Arial,Helvetica,sans-serif;color:#111827;">
    ${headerBlock}
  </body>
</html>
  `.trim();

  newItems.push({
    json: {
      meta,
      sections,
      email: {
        subject: subjectOut || '',
        body_text: bodyText,
        body_html: fullHtml,
      },
      raw: data,
    },
  });
}

return newItems;

// This Function node expects the AI Agent's result in item.json.output
// Node type MUST be "Function" (not "Function Item")

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&quot;')
    .replace(/'/g, '&#39;');
}

const newItems = [];

for (const item of items) {
  let data;

  // 1) Get the agent output
  let raw = item.json.output;

  if (raw && typeof raw === 'object') {
    // already parsed
    data = raw;
  } else if (typeof raw === 'string') {
    raw = raw.trim();

    // strip ```json fences if present
    if (raw.startsWith('```')) {
      raw = raw.replace(/^```[a-zA-Z]*\s*/m, '');
      raw = raw.replace(/```[\s]*$/m, '');
      raw = raw.trim();
    }

    if (!raw) {
      newItems.push(item);
      continue;
    }

    try {
      data = JSON.parse(raw);
    } catch (err) {
      newItems.push({
        json: {
          ...item.json,
          _parseError: 'Failed to parse AI output as JSON',
          _rawOutput: raw,
          _errorMessage: err.message,
        },
      });
      continue;
    }
  } else {
    // no usable output
    newItems.push(item);
    continue;
  }

  // 2) Pull pieces out
  const meta      = data.meta || {};
  const sections  = data.sections || {};
  const email     = data.email || {};

  const painPoints       = sections.pain_points || [];
  const va               = sections.va_discussion || {};
  const milestones       = sections.milestones || [];
  const pdevDeliverables = sections.pdev_deliverables || [];
  const nextSteps        = sections.next_steps || [];
  const nextMeeting      = sections.next_meeting || {};
  const bodyText         = email.body || '';

  // 3) Subject: Meeting Summary - {clientName} - {meetingTitle}
  const clientName   = meta.clientName || meta.client || '';
  const meetingTitle = meta.meetingTitle || '';
  let subjectOut     = email.subject || '';

  if (clientName || meetingTitle) {
    const clientLabel = clientName || 'Client';
    const titleLabel  = meetingTitle || 'Meeting';
    subjectOut = `Meeting Summary - ${clientLabel} - ${titleLabel}`;
  }

  // 4) Key Focus Areas & Opportunities (use full summary from AI)
  let painPointsSection = '';
  if (Array.isArray(painPoints) && painPoints.length > 0) {
    const itemsList = painPoints.map(p => {
      const category = p.category ? `${escapeHtml(p.category)}: ` : '';
      const summary  = escapeHtml(p.summary || '');
      return `<li style="margin-bottom:8px;font-size:14px;line-height:20px;">${category}${summary}</li>`;
    });

    painPointsSection = `
      <div style="margin-top:16px; margin-bottom:16px;">
        <h3 style="margin:0 0 8px 0;">Key Focus Areas &amp; Opportunities</h3>
        <ul style="margin:0 0 10px 20px; padding:0 0 0 18px; list-style-type:disc;">
          ${itemsList.join('')}
        </ul>
      </div>
    `;
  }

  // 5) VA Discussion
  let vaSection = '';
  const hasVaContent =
    (Array.isArray(va.primary_tasks) && va.primary_tasks.length > 0) ||
    va.onboarding_timeline;

  if (hasVaContent) {
    const primaryTasks = Array.isArray(va.primary_tasks) ? va.primary_tasks : [];

    const tasksList = primaryTasks.length
      ? `<ul style="margin:4px 0 10px 20px; padding:0 0 0 18px; list-style-type:disc;">
           ${primaryTasks.map(t => `<li style="font-size:14px;line-height:20px;">${escapeHtml(t)}</li>`).join('')}
         </ul>`
      : '';

    let timelineText = (va.onboarding_timeline || '').trim();
    const tlLower = timelineText.toLowerCase();
    if (tlLower.includes('ongoing') && (tlLower.includes('workflow') || tlLower.includes('process'))) {
      timelineText = 'We will continue refining this workflow over time.';
    }

    vaSection = `
      <div style="margin-top:16px; margin-bottom:16px;">
        <h3 style="margin:0 0 8px 0;">VA Discussion</h3>
        ${primaryTasks.length ? `<p style="margin:8px 0 4px 0;font-size:14px;line-height:20px;"><strong>Primary Tasks:</strong></p>${tasksList}` : ''}
        ${timelineText ? `<p style="margin:8px 0 0 0;font-size:14px;line-height:20px;"><strong>Onboarding / Timeline:</strong> ${escapeHtml(timelineText)}</p>` : ''}
      </div>
    `;
  }

  // 6) Milestones table (Milestone name + visible description)
  let milestonesSection = '';
  const realMilestones = (Array.isArray(milestones) ? milestones : []).filter(m => {
    const desc = (m.description || m.name || '').trim().toLowerCase();
    return desc && desc !== 'none discussed.';
  });

  if (realMilestones.length > 0) {
    milestonesSection = `
      <div style="margin-top:16px; margin-bottom:16px;">
        <h3 style="margin:0 0 8px 0;">Milestones</h3>
        <table border="1" cellpadding="6" cellspacing="0"
               style="border-collapse:collapse; width:100%; border:1px solid #e5e7eb; table-layout:fixed; font-size:14px;line-height:20px;">
          <colgroup>
            <col style="width:50%;">
            <col style="width:20%;">
            <col style="width:15%;">
            <col style="width:15%;">
          </colgroup>
          <thead>
            <tr style="background:#f9fafb;">
              <th style="text-align:center;font-size:14px;line-height:20px;">Milestone</th>
              <th style="text-align:center;font-size:14px;line-height:20px;">Owner</th>
              <th style="text-align:center;font-size:14px;line-height:20px;">Status</th>
              <th style="text-align:center;font-size:14px;line-height:20px;">Target Date</th>
            </tr>
          </thead>
          <tbody>
            ${realMilestones.map(m => {
              // Prefer explicit name from AI; fall back to first sentence of description
              let name = (m.name || '').trim();
              const fullDesc = String(m.description || '').trim();
              if (!name) {
                name = fullDesc.split(/\.|\n/)[0] || fullDesc;
              }

              const descHtml = fullDesc
                ? `<div style="margin-top:4px;font-size:14px;line-height:20px;color:#4b5563;">
                     ${escapeHtml(fullDesc)}
                   </div>`
                : '';

              return `
                <tr>
                  <td style="vertical-align:top;font-size:14px;line-height:20px;">
                    <strong>${escapeHtml(name)}</strong>
                    ${descHtml}
                  </td>
                  <td style="vertical-align:top; text-align:center;font-size:14px;line-height:20px;">${escapeHtml(m.owner || 'TBD')}</td>
                  <td style="vertical-align:top; text-align:center;font-size:14px;line-height:20px;">${escapeHtml(m.status || 'Planned')}</td>
                  <td style="vertical-align:top; text-align:center;font-size:14px;line-height:20px;">${escapeHtml(m.target_date || 'TBD')}</td>
                </tr>
              `;
            }).join('')}
          </tbody>
        </table>
      </div>
    `;
  }

  // 7) PDEV Deliverables table
  let pdevSection = '';
  const realPdev = (Array.isArray(pdevDeliverables) ? pdevDeliverables : []).filter(d => {
    const name = (d.name || '').trim().toLowerCase();
    const desc = (d.description || '').trim().toLowerCase();
    return (name || desc) && name !== 'none discussed.' && desc !== 'none discussed.';
  });

  if (realPdev.length > 0) {
    pdevSection = `
      <div style="margin-top:16px; margin-bottom:16px;">
        <h3 style="margin:0 0 8px 0;">Process Development Deliverables</h3>
        <table border="1" cellpadding="6" cellspacing="0"
               style="border-collapse:collapse; width:100%; border:1px solid #e5e7eb; table-layout:fixed; font-size:14px;line-height:20px;">
          <colgroup>
            <col style="width:40%;">
            <col style="width:15%;">
            <col style="width:15%;">
            <col style="width:15%;">
            <col style="width:15%;">
          </colgroup>
          <thead>
            <tr style="background:#f9fafb;">
              <th style="text-align:center;font-size:14px;line-height:20px;">Deliverable</th>
              <th style="text-align:center;font-size:14px;line-height:20px;">Type</th>
              <th style="text-align:center;font-size:14px;line-height:20px;">Owner</th>
              <th style="text-align:center;font-size:14px;line-height:20px;">Status</th>
              <th style="text-align:center;font-size:14px;line-height:20px;">Due Date</th>
            </tr>
          </thead>
          <tbody>
            ${realPdev.map(d => {
              const name = escapeHtml(d.name || '');
              const desc = String(d.description || '').trim();
              const descHtml = desc
                ? `<div style="margin-top:4px;font-size:14px;line-height:20px;color:#4b5563;">
                     ${escapeHtml(desc)}
                   </div>`
                : '';

              return `
                <tr>
                  <td style="vertical-align:top;font-size:14px;line-height:20px;">
                    <strong>${name}</strong>
                    ${descHtml}
                  </td>
                  <td style="vertical-align:top;text-align:center;font-size:14px;line-height:20px;">${escapeHtml(d.type || 'TBD')}</td>
                  <td style="vertical-align:top;text-align:center;font-size:14px;line-height:20px;">${escapeHtml(d.owner || 'TBD')}</td>
                  <td style="vertical-align:top;text-align:center;font-size:14px;line-height:20px;">${escapeHtml(d.status || 'Planned')}</td>
                  <td style="vertical-align:top;text-align:center;font-size:14px;line-height:20px;">${escapeHtml(d.due_date || 'TBD')}</td>
                </tr>
              `;
            }).join('')}
          </tbody>
        </table>
      </div>
    `;
  }

  // 8) Next Steps list
  let nextStepsSection = '';
  if (Array.isArray(nextSteps) && nextSteps.length > 0) {
    const itemsList = nextSteps.map(s => {
      const owner = s.owner || 'TBD';
      const action = s.action || '';
      const due = s.due_date && s.due_date !== 'TBD'
        ? ` (Due: ${s.due_date})`
        : '';
      return `<li style="font-size:14px;line-height:20px;">${escapeHtml(owner)} to ${escapeHtml(action)}${escapeHtml(due)}</li>`;
    });

    nextStepsSection = `
      <div style="margin-top:16px; margin-bottom:16px;">
        <h3 style="margin:0 0 8px 0;">Next Steps</h3>
        <ul style="margin:0 0 10px 20px; padding:0 0 0 18px; list-style-type:disc;">
          ${itemsList.join('')}
        </ul>
      </div>
    `;
  }

  // 9) Next Meeting Schedule
  let nextMeetingSection = '';
  if (nextMeeting && typeof nextMeeting === 'object' && Object.keys(nextMeeting).length > 0) {
    const rawDate = (nextMeeting.date || '').trim();
    const rawTime = (nextMeeting.time || '').trim();
    const nmTz    = (nextMeeting.timezone || '').trim();
    const nmNote  = (nextMeeting.notes || '').trim(); // agenda / purpose

    const parts = [];
    if (rawDate && rawDate.toUpperCase() !== 'TBD') parts.push(rawDate);
    if (rawTime && rawTime.toUpperCase() !== 'TBD') parts.push(rawTime);
    if (nmTz) parts.push(nmTz);

    const whenText = parts.join(' • ');

    const agendaHtml = nmNote
      ? `<p style="margin:4px 0 0 0;font-size:14px;line-height:20px;"><strong>Agenda:</strong> ${escapeHtml(nmNote)}</p>`
      : '';

    if (whenText || agendaHtml) {
      nextMeetingSection = `
        <div style="margin-top:16px; margin-bottom:16px;">
          <h3 style="margin:0 0 8px 0;">Next Meeting Schedule</h3>
          ${
            whenText
              ? `<p style="margin:0;font-size:14px;line-height:20px;"><strong>Date &amp; Time:</strong> ${escapeHtml(whenText)}</p>`
              : ''
          }
          ${agendaHtml}
        </div>
      `;
    }
  }

  // 10) Intro from plain-text body (skip duplicated sections)
  const lines = String(bodyText || '').split('\n');

  const introParts = [];
  let i = 0;
  let signoffLines = [];

  while (i < lines.length) {
    let line = lines[i].trim();

    if (!line) {
      i++;
      continue;
    }

    // Skip duplicated headings if AI ever adds them
    if (/^Key Focus Areas[:]?/i.test(line) || /^Milestones[:]?/i.test(line) ||
        /^Next Steps[:]?/i.test(line) || /^Process Development Deliverables[:]?/i.test(line)) {
      i++;
      while (i < lines.length) {
        const l2 = lines[i].trim();
        if (!l2) { i++; continue; }
        if (!l2.startsWith('- ')) break;
        i++;
      }
      continue;
    }

    if (line === 'Key Discussion Points:') {
      i++;
      while (i < lines.length) {
        const l2 = lines[i].trim();
        if (!l2) { i++; continue; }
        if (!l2.startsWith('- ')) break;
        i++;
      }
      continue;
    }

    if (/^best\b/i.test(line)) {
      // capture signoff for name extraction
      signoffLines.push(line);
      i++;
      while (i < lines.length) {
        const l2 = lines[i].trim();
        if (!l2) break;
        signoffLines.push(l2);
        i++;
      }
      continue;
    }

    const paraLines = [line];
    i++;

    while (i < lines.length) {
      const l2 = lines[i].trim();
      if (
        !l2 ||
        l2 === 'Key Discussion Points:' ||
        /^next steps[:]?$/i.test(l2) ||
        /^best\b/i.test(l2) ||
        l2.startsWith('- ')
      ) {
        break;
      }
      paraLines.push(l2);
      i++;
    }

    const paraText = paraLines.join(' ');

    if (/Please let me know if you have any questions/i.test(paraText)) {
      continue;
    }

    const htmlPara = `<p style="margin:0 0 16px 0; font-size:14px; line-height:20px;">${escapeHtml(paraText)}</p>`;
    introParts.push(htmlPara);
  }

  // 11) Sign-off
  let signName = '';

  if (signoffLines.length > 0) {
    for (let j = signoffLines.length - 1; j >= 0; j--) {
      const l = signoffLines[j].trim();
      if (l && !/^best\b/i.test(l)) {
        signName = l;
        break;
      }
    }
  }

  if (!signName) {
    signName = 'SV Process Engineering Team';
  }

  const signoffHtml = [
    `<p style="margin:0 0 12px 0; font-size:14px; line-height:20px;">Best regards,</p>`,
    `<p style="margin:0 0 12px 0; font-size:14px; line-height:20px;">${escapeHtml(signName)}</p>`
  ].join('\n');

  // 12) Combine sections into inner content
  const detailSections = [
    painPointsSection,
    vaSection,
    milestonesSection,
    pdevSection,
    nextStepsSection,
    nextMeetingSection,
  ].filter(Boolean).join('\n');

  const customClosing = `<p style="margin:16px 0 12px 0; font-size:14px; line-height:20px;">If there’s anything I missed or if you’d like to adjust any of the milestones or deliverables, please feel free to let me know.</p>`;

  let finalHtml = '';

  finalHtml += introParts.join('\n');

  if (detailSections) {
    finalHtml += '\n' + detailSections;
  }

  finalHtml += '\n' + customClosing;
  finalHtml += '\n' + signoffHtml;

  // 13) Wrap in card layout with wider centered orange header (720px)
  const safeMeetingTitle = meetingTitle || 'Minutes of the Meeting';

  const headerBlock = `
    <table role="presentation" cellpadding="0" cellspacing="0" width="100%">
      <tr>
        <td align="center" style="padding:24px;">
          <table role="presentation" cellpadding="0" cellspacing="0" width="720" style="max-width:720px;background:#ffffff;border-radius:12px;overflow:hidden;border:1px solid #e5e7eb;">
            <tr>
              <td style="background:#ea7b21;color:#ffffff;padding:20px 28px;border-radius:12px 12px 0 0;text-align:center;">
                <h1 style="margin:0 0 4px 0;font-size:22px;line-height:28px;font-weight:700;font-family:Arial,Helvetica,sans-serif;">
                  Minutes of the Meeting
                </h1>
                <p style="margin:0;font-size:13px;line-height:18px;font-family:Arial,Helvetica,sans-serif;">
                  ${escapeHtml(safeMeetingTitle)}
                </p>
              </td>
            </tr>
            <tr>
              <td style="padding:24px 28px 28px 28px;background:#ffffff;font-size:14px;line-height:20px;">
                ${finalHtml.trim()}
              </td>
            </tr>
          </table>
        </td>
      </tr>
    </table>
  `.trim();

  const fullHtml = `
<!DOCTYPE html>
<html>
  <head>
    <meta charset="utf-8" />
    <title>${escapeHtml(subjectOut || '')}</title>
  </head>
  <body style="margin:0;padding:0;background:#f3f4f6;font-family:Arial,Helvetica,sans-serif;color:#111827;">
    ${headerBlock}
  </body>
</html>
  `.trim();

  newItems.push({
    json: {
      meta,
      sections,
      email: {
        subject: subjectOut || '',
        body_text: bodyText,
        body_html: fullHtml,
      },
      raw: data,
    },
  });
}

return newItems;

