// Initialize an array to hold just the email strings
const emailList = [];

// Loop through incoming data
for (const item of items) {
  const invitees = item.json.body.calendar_invitees;

  if (invitees && Array.isArray(invitees)) {
    invitees.forEach(person => {
      // Filter out the google calendar group/bot email
      if (person.email && !person.email.includes("group.calendar.google.com")) {
        emailList.push(person.email);
      }
    });
  }
}

// --- UPDATED SECTION ---
// Create a formula string that forces both sides to be lowercase
// This creates: OR(LOWER({Email})='test@test.com', LOWER({Email})='test2@test.com')
const airtableFormula = "OR(" + emailList.map(e => `LOWER({Email}) = '${e.toLowerCase()}'`).join(",") + ")";

// Return a SINGLE item containing the list
return [{
  json: {
    email_array: emailList,
    email_string: emailList.join(", "), 
    airtable_search_formula: airtableFormula 
  }
}];

